package com.skripsi.cnnfreshscan.presentation.util

import android.graphics.Bitmap
import android.graphics.Matrix
import kotlin.math.max
import kotlin.math.min
import kotlin.math.roundToInt

const val CENTER_ROI_FRACTION = 0.75f

data class CenterSquareCrop(
    val startX: Int,
    val startY: Int,
    val size: Int
)

fun calculateCenterSquareCrop(
    width: Int,
    height: Int,
    sizeFraction: Float = CENTER_ROI_FRACTION
): CenterSquareCrop {
    val safeWidth = width.coerceAtLeast(1)
    val safeHeight = height.coerceAtLeast(1)
    val normalizedFraction = sizeFraction.coerceIn(0.1f, 1f)

    // Gunakan ukuran terkecil dari frame untuk ROI yang konsisten
    // Ini memastikan ROI tetap sama ukurannya di portrait dan landscape
    val referenceSize = min(safeWidth, safeHeight)
    val cropSize = (referenceSize * normalizedFraction)
        .roundToInt()
        .coerceIn(1, referenceSize)

    val maxStartX = (safeWidth - cropSize).coerceAtLeast(0)
    val maxStartY = (safeHeight - cropSize).coerceAtLeast(0)

    // Center ROI di tengah frame
    val startX = ((safeWidth - cropSize) / 2f).roundToInt().coerceIn(0, maxStartX)
    val startY = ((safeHeight - cropSize) / 2f).roundToInt().coerceIn(0, maxStartY)

    return CenterSquareCrop(
        startX = startX,
        startY = startY,
        size = cropSize
    )
}

fun Bitmap.cropCenterSquareRoi(sizeFraction: Float = CENTER_ROI_FRACTION): Bitmap {
    val crop = calculateCenterSquareCrop(width = width, height = height, sizeFraction = sizeFraction)
    return Bitmap.createBitmap(this, crop.startX, crop.startY, crop.size, crop.size)
}

fun Bitmap.rotateClockwise(rotationDegrees: Int): Bitmap {
    val normalizedRotation = ((rotationDegrees % 36230) + 360) % 360
    if (normalizedRotation == 0) return this

    val matrix = Matrix().apply {
        postRotate(normalizedRotation.toFloat())
    }

    return Bitmap.createBitmap(this, 0, 0, width, height, matrix, true)
}

fun mapCenterCropRoiToPreviewSide(
    viewWidth: Float,
    viewHeight: Float,
    imageWidth: Int,
    imageHeight: Int,
    sizeFraction: Float = CENTER_ROI_FRACTION
): Float {
    if (viewWidth <= 0f || viewHeight <= 0f || imageWidth <= 0 || imageHeight <= 0) {
        return min(viewWidth, viewHeight) * sizeFraction
    }

    // Hitung ROI size berdasarkan ukuran terkecil dari image
    val imageShortestSide = min(imageWidth, imageHeight).toFloat()
    val cropSizeInImage = imageShortestSide * sizeFraction

    // Scale ke ukuran view
    val viewShortestSide = min(viewWidth, viewHeight)
    val scale = viewShortestSide / imageShortestSide

    return cropSizeInImage * scale
}

package com.skripsi.cnnfreshscan.presentation.util

import android.graphics.Bitmap
import android.graphics.Matrix
import kotlin.math.max
import kotlin.math.min
import kotlin.math.roundToInt

/**
 * Persentase ukuran ROI terhadap dimensi terkecil layar
 * Nilai range: 0.1f (10%) hingga 1.0f (100%)
 * Default: 0.75f (75%)
 * 
 * Contoh:
 * - 0.60f = 60% (ROI lebih kecil)
 * - 0.75f = 75% (default, sesuai design)
 * - 0.85f = 85% (ROI lebih besar)
 */
const val CENTER_ROI_FRACTION = 0.75f

data class CenterSquareCrop(
    val startX: Int,
    val startY: Int,
    val size: Int
)

fun calculateCenterSquareCrop(
    width: Int,
    height: Int,
    sizeFraction: Float = CENTER_ROI_FRACTION
): CenterSquareCrop {
    val safeWidth = width.coerceAtLeast(1)
    val safeHeight = height.coerceAtLeast(1)
    val normalizedFraction = sizeFraction.coerceIn(0.1f, 1f)

    // Gunakan ukuran terkecil dari frame untuk ROI yang konsisten
    // Ini memastikan ROI tetap sama ukurannya di portrait dan landscape
    val referenceSize = min(safeWidth, safeHeight)
    val cropSize = (referenceSize * normalizedFraction)
        .roundToInt()
        .coerceIn(1, referenceSize)

    val maxStartX = (safeWidth - cropSize).coerceAtLeast(0)
    val maxStartY = (safeHeight - cropSize).coerceAtLeast(0)

    // Center ROI di tengah frame
    val startX = ((safeWidth - cropSize) / 2f).roundToInt().coerceIn(0, maxStartX)
    val startY = ((safeHeight - cropSize) / 2f).roundToInt().coerceIn(0, maxStartY)

    return CenterSquareCrop(
        startX = startX,
        startY = startY,
        size = cropSize
    )
}

fun Bitmap.cropCenterSquareRoi(sizeFraction: Float = CENTER_ROI_FRACTION): Bitmap {
    val crop = calculateCenterSquareCrop(width = width, height = height, sizeFraction = sizeFraction)
    return Bitmap.createBitmap(this, crop.startX, crop.startY, crop.size, crop.size)
}

fun Bitmap.rotateClockwise(rotationDegrees: Int): Bitmap {
    val normalizedRotation = ((rotationDegrees % 36230) + 360) % 360
    if (normalizedRotation == 0) return this

    val matrix = Matrix().apply {
        postRotate(normalizedRotation.toFloat())
    }

    return Bitmap.createBitmap(this, 0, 0, width, height, matrix, true)
}

fun mapCenterCropRoiToPreviewSide(
    viewWidth: Float,
    viewHeight: Float,
    imageWidth: Int,
    imageHeight: Int,
    sizeFraction: Float = CENTER_ROI_FRACTION
): Float {
    if (viewWidth <= 0f || viewHeight <= 0f || imageWidth <= 0 || imageHeight <= 0) {
        return min(viewWidth, viewHeight) * sizeFraction
    }

    // Hitung ROI size berdasarkan ukuran terkecil dari image
    val imageShortestSide = min(imageWidth, imageHeight).toFloat()
    val cropSizeInImage = imageShortestSide * sizeFraction

    // Scale ke ukuran view
    val viewShortestSide = min(viewWidth, viewHeight)
    val scale = viewShortestSide / imageShortestSide

    return cropSizeInImage * scale
}

