@Composable
private fun CenterScannerSection(
    modifier: Modifier = Modifier,
    instructionText: String = "Arahkan Buah/Sayur di Dalam Area Pindai",
    roiSizeFraction: Float = 0.75f,
    roiVerticalBias: Float = -0.22f,
    label: String,
    confidence: Float,
    predictionTimeMs: Long?,
) {
    val safeRoiFraction = roiSizeFraction.coerceIn(0.1f, 1f)
    BoxWithConstraints(
        modifier = modifier
            .fillMaxSize()
            .padding(horizontal = 20.dp)
    ) {
        val roiSide = minOf(maxWidth, maxHeight) * safeRoiFraction
        val maxTop = maxHeight - roiSide
        val centeredTop = maxTop / 2f
        val shiftedTop = centeredTop + centeredTop * roiVerticalBias.coerceIn(-0.45f, 0.45f)
        val roiTop = when {
            shiftedTop < 0.dp -> 0.dp
            shiftedTop > maxTop -> maxTop
            else -> shiftedTop
        }
        val instructionTop = (roiTop - 48.dp).coerceAtLeast(78.dp)
        val cardTop = roiTop + roiSide + 10.dp

        Text(
            text = instructionText,
            color = Color.White,
            style = MaterialTheme.typography.titleSmall,
            textAlign = TextAlign.Center,
            modifier = Modifier
                .fillMaxWidth()
                .offset(y = instructionTop)
        )

        Box(
            modifier = Modifier
                .align(Alignment.TopCenter)
                .offset(y = roiTop)
                .width(roiSide)
                .aspectRatio(1f)
        )

        LivePredictionCard(
            label = label,
            confidence = confidence,
            predictionTimeMs = predictionTimeMs,
            modifier = Modifier
                .align(Alignment.TopCenter)
                .offset(y = cardTop)
                .fillMaxWidth()
        )
    }
}

