/**
 * Verifies that all essential camera screen elements are displayed
 * @param testRule The ComposeTestRule instance
 */
fun assertAllCameraScreenElementsDisplayed(testRule: ComposeTestRule) {
    testRule.onNodeWithContentDescription("Camera preview")
        .assertIsDisplayed()

    testRule.onNodeWithContentDescription("Ambil Foto")
        .assertIsDisplayed()

    testRule.onNodeWithContentDescription("Ambil Gambar dari Galeri")
        .assertIsDisplayed()

    testRule.onNodeWithText("Arahkan buah dan sayur ke area pindai")
        .assertIsDisplayed()
}

