 * @param testRule The ComposeTestRule instance
 */
fun assertCameraPreviewDisplayed(testRule: ComposeTestRule) {
    testRule.onNodeWithContentDescription("Camera preview")
        .assertIsDisplayed()
}

/**
 * Verifies navigation back button is available
 * @param testRule The ComposeTestRule instance
 */
fun assertNavigationBackButtonAvailable(testRule: ComposeTestRule) {
    testRule.onNodeWithContentDescription("Kembali")
        .assertIsDisplayed()
}

/**
 * Verifies all accessibility labels are present
 * @param testRule The ComposeTestRule instance
 * @return Boolean indicating if all labels are accessible
 */
fun verifyAllAccessibilityLabels(testRule: ComposeTestRule): Boolean {
    return try {
        testRule.onNodeWithContentDescription("Camera preview")
            .assertIsDisplayed()
        testRule.onNodeWithContentDescription("Ambil Foto")
            .assertIsDisplayed()
        testRule.onNodeWithContentDescription("Ambil Gambar dari Galeri")
            .assertIsDisplayed()
        testRule.onNodeWithContentDescription("Ganti Kamera")
            .assertIsDisplayed()
        true
    } catch (e: Exception) {
        false
    }
}

/**
 * Verifies classification result display
 * @param testRule The ComposeTestRule instance
 */
fun assertClassificationResultDisplayed(testRule: ComposeTestRule) {
    testRule.onNodeWithText("Hasil Pemindaian")
        .assertIsDisplayed()
}

/**
 * Verifies instruction text is visible and readable
 * @param testRule The ComposeTestRule instance
 */
fun assertInstructionTextVisible(testRule: ComposeTestRule) {
    testRule.onNodeWithText("Arahkan buah dan sayur ke area pindai")
        .assertIsDisplayed()
}

/**
 * Performs stress test with rapid button clicks
 * @param testRule The ComposeTestRule instance
 * @param contentDescription Description of button to click
 * @param clickCount Number of times to click
 */
fun performStressTestClicks(
    testRule: ComposeTestRule,
    contentDescription: String,
    clickCount: Int = 10
) {
    repeat(clickCount) {
        try {
            testRule.onNodeWithContentDescription(contentDescription)
                .assertIsDisplayed()
        } catch (e: Exception) {
            throw AssertionError("Button $contentDescription not found during stress test at iteration $it")
        }
    }
}

/**
 * Verifies screen content consistency
 * @param testRule The ComposeTestRule instance
 * @param elements List of content descriptions to verify
 */
fun assertScreenContentConsistency(
    testRule: ComposeTestRule,
    elements: List<String>
) {
    elements.forEach { element ->
        testRule.onNodeWithContentDescription(element)
            .assertIsDisplayed()
    }
}

/**
 * Verifies text elements on screen
 * @param testRule The ComposeTestRule instance
 * @param textElements List of text to verify
 */
fun assertTextElementsVisible(
    testRule: ComposeTestRule,
    textElements: List<String>
) {
    textElements.forEach { text ->
        testRule.onNodeWithText(text)
            .assertIsDisplayed()
    }
}

/**
 * Comprehensive accessibility verification
 * @param testRule The ComposeTestRule instance
 * @return Map of accessibility verification results
 */
fun performComprehensiveAccessibilityCheck(testRule: ComposeTestRule): Map<String, Boolean> {
    return mapOf(
        "Camera Preview" to canFindElement(testRule, "Camera preview"),
        "Capture Button" to canFindElement(testRule, "Ambil Foto"),
        "Gallery Button" to canFindElement(testRule, "Ambil Gambar dari Galeri"),
        "Camera Switch" to canFindElement(testRule, "Ganti Kamera"),
        "Instruction Text" to canFindTextElement(testRule, "Arahkan buah dan sayur ke area pindai"),
        "Result Title" to canFindTextElement(testRule, "Hasil Pemindaian"),
        "Back Button" to canFindElement(testRule, "Kembali")
    )
}

/**
 * Helper function to check if element exists
 * @param testRule The ComposeTestRule instance
 * @param contentDescription Content description to find
 * @return Boolean indicating if element was found
 */
private fun canFindElement(testRule: ComposeTestRule, contentDescription: String): Boolean {
    return try {
        testRule.onNodeWithContentDescription(contentDescription)
            .assertIsDisplayed()
        true
    } catch (e: Exception) {
        false
    }
}

/**
 * Helper function to check if text element exists
 * @param testRule The ComposeTestRule instance
 * @param text Text to find
 * @return Boolean indicating if element was found
 */
private fun canFindTextElement(testRule: ComposeTestRule, text: String): Boolean {
    return try {
        testRule.onNodeWithText(text)
            .assertIsDisplayed()
        true
    } catch (e: Exception) {
        false
    }
}

/**
 * Enum for test status tracking
 */
enum class TestStatus {
    PASSED,
    FAILED,
    SKIPPED,
    TIMEOUT
}

/**
 * Data class for test result reporting
 */
data class TestResult(
    val testName: String,
    val status: TestStatus,
    val duration: Long,
    val errorMessage: String? = null
)

/**
 * Logs test result
 * @param testName Name of the test
 * @param status Status of the test
 * @param duration Duration in milliseconds
 * @param errorMessage Optional error message
 */
fun logTestResult(
    testName: String,
    status: TestStatus,
    duration: Long,
    errorMessage: String? = null
) {
    val statusStr = status.name.padEnd(8)
    val durationStr = "${duration}ms".padEnd(12)
    val errorStr = errorMessage?.let { " - $it" } ?: ""

    println("TEST: $testName")
    println("STATUS: $statusStr | DURATION: $durationStr $errorStr")
    println("---")
}

